import{_ as e,o as a,c as l,a7 as r}from"./chunks/framework.C5fSpjcB.js";const b=JSON.parse('{"title":"メインストーリー","description":"","frontmatter":{},"headers":[],"relativePath":"ja/story/main.md","filePath":"ja/story/main.md","lastUpdated":1775394001000}'),i={name:"ja/story/main.md"};function d(n,t,o,s,h,c){return a(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="メインストーリー" tabindex="-1">メインストーリー <a class="header-anchor" href="#メインストーリー" aria-label="Permalink to &quot;メインストーリー&quot;">​</a></h1><p>忘却前夜のメインストーリーのあらすじと章解説です。総テキスト量は約80万字で、単元劇形式で展開されます。</p><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>以下の内容にはストーリーのネタバレが含まれます。未読の方はご注意ください。</p></div><h2 id="忘却篇-oblivion-chapter" tabindex="-1">忘却篇（Oblivion Chapter） <a class="header-anchor" href="#忘却篇-oblivion-chapter" aria-label="Permalink to &quot;忘却篇（Oblivion Chapter）&quot;">​</a></h2><h3 id="プロローグ" tabindex="-1">プロローグ <a class="header-anchor" href="#プロローグ" aria-label="Permalink to &quot;プロローグ&quot;">​</a></h3><p>守密人の旅が始まる序章。弥萨格大学に到着した主人公は、融蝕という見えない災厄の存在を知る。記憶を失った原因を調査するため、覚醒体たちと共に未知の真相へと踏み出す。</p><blockquote><p>「弥萨格大学へようこそ、守密人。だが祝うことは何もない――あなたは誰にも知られず、誰にも称えられず、誰にも記憶されない。」</p></blockquote><h3 id="第1章-東区秘事-east-district-secrets" tabindex="-1">第1章：東区秘事（East District Secrets） <a class="header-anchor" href="#第1章-東区秘事-east-district-secrets" aria-label="Permalink to &quot;第1章：東区秘事（East District Secrets）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">節</th><th style="text-align:left;">タイトル</th></tr></thead><tbody><tr><td style="text-align:center;">1-1</td><td style="text-align:left;">漆黒之夢 (Dream of Darkness)</td></tr><tr><td style="text-align:center;">1-2</td><td style="text-align:left;">人不可貌相 (Don&#39;t Judge By Appearance)</td></tr><tr><td style="text-align:center;">1-3</td><td style="text-align:left;">地下の幽霊 (Underground Phantom)</td></tr><tr><td style="text-align:center;">1-4</td><td style="text-align:left;">小小偵探 (Little Detective)</td></tr><tr><td style="text-align:center;">1-5</td><td style="text-align:left;">病 (Illness)</td></tr><tr><td style="text-align:center;">1-6</td><td style="text-align:left;">非礼勿言 (Speak No Evil)</td></tr><tr><td style="text-align:center;">1-7</td><td style="text-align:left;">誰が殺した知更鳥 (Who Killed the Robin?)</td></tr><tr><td style="text-align:center;">1-8</td><td style="text-align:left;">内在的危険 (Inner Danger)</td></tr><tr><td style="text-align:center;">1-9</td><td style="text-align:left;">我々の秘密 (Our Secret)</td></tr><tr><td style="text-align:center;">1-10</td><td style="text-align:left;">甘美な芸術 (The Sweet Art)</td></tr></tbody></table><p>調査は層を重ねて深まっていく。まず工坊の管理者、次に怪しい医者、そして邪教組織の疑いへ。最終的な真相の核心には、一人のコントロールされた哀れな少女がいた。彼女は家族と仲間を守るため、自ら命を絶つことを選んだ。</p><h3 id="第2章-蜕変-metamorphosis" tabindex="-1">第2章：蜕変（Metamorphosis） <a class="header-anchor" href="#第2章-蜕変-metamorphosis" aria-label="Permalink to &quot;第2章：蜕変（Metamorphosis）&quot;">​</a></h3><p>メインストーリー第二章。融蝕の脅威がさらに深刻になり、守密人は新たな覚醒体たちと出会いながら、世界の裏側に潜む秘密に迫る。</p><h3 id="第3章" tabindex="-1">第3章 <a class="header-anchor" href="#第3章" aria-label="Permalink to &quot;第3章&quot;">​</a></h3><p>メインストーリー第三章。物語の核心に近づくにつれ、組織間の対立と陰謀が明らかになっていく。</p><h3 id="第4章" tabindex="-1">第4章 <a class="header-anchor" href="#第4章" aria-label="Permalink to &quot;第4章&quot;">​</a></h3><p>重大な転換点。角色たちが救い出した少女・莉莉を療養院に連れて行くが、そこでさらに大きな危機と秘密が潜んでいることを発見する。プレイヤーの選択が後続のストーリー展開に影響する。</p><h3 id="第5章" tabindex="-1">第5章 <a class="header-anchor" href="#第5章" aria-label="Permalink to &quot;第5章&quot;">​</a></h3><p>メインストーリー第五章。一度閉鎖された後に再開放され、補償報酬が配布された。</p><h3 id="第6章" tabindex="-1">第6章 <a class="header-anchor" href="#第6章" aria-label="Permalink to &quot;第6章&quot;">​</a></h3><p>メインストーリー第六章。調査行動の章節報酬として特批薬剤が獲得可能（第6章=35個）。</p><h3 id="第7章" tabindex="-1">第7章 <a class="header-anchor" href="#第7章" aria-label="Permalink to &quot;第7章&quot;">​</a></h3><p>ボス章節を含むメインストーリー第七章。7-18「火種(Kindling)」等のボス戦が展開される。</p><h2 id="星辰篇-stellar-chapter" tabindex="-1">星辰篇（Stellar Chapter） <a class="header-anchor" href="#星辰篇-stellar-chapter" aria-label="Permalink to &quot;星辰篇（Stellar Chapter）&quot;">​</a></h2><p>v2.0アップデートで追加された新章「星辰正位之刻」。編成ルールの大改革（任意2界域混編解禁）、鍵令システムの実装、混沌界域のリメイクなど、ゲームプレイにも大きな変革をもたらした。</p><h3 id="星辰篇序章" tabindex="-1">星辰篇序章 <a class="header-anchor" href="#星辰篇序章" aria-label="Permalink to &quot;星辰篇序章&quot;">​</a></h3><p>星辰篇の幕開け。新たな時代の始まりと、これまでの物語を引き継ぐ新章の導入。</p><h3 id="星辰篇第1章-1-1〜1-14" tabindex="-1">星辰篇第1章（1-1〜1-14） <a class="header-anchor" href="#星辰篇第1章-1-1〜1-14" aria-label="Permalink to &quot;星辰篇第1章（1-1〜1-14）&quot;">​</a></h3><p>星辰正位之刻の第一章。新限定キャラクター・克莱门汀（超維）と克珀珊特（深海）が登場。</p><h3 id="星辰篇第2章-蜕変-2-1〜2-18" tabindex="-1">星辰篇第2章：蜕変（2-1〜2-18） <a class="header-anchor" href="#星辰篇第2章-蜕変-2-1〜2-18" aria-label="Permalink to &quot;星辰篇第2章：蜕変（2-1〜2-18）&quot;">​</a></h3><p>星辰篇第二章。新限定キャラクター・凯蒂古拉（混沌）とカ斯托尔（超維）が登場。</p><h3 id="星辰篇第3章-3-1〜3-11" tabindex="-1">星辰篇第3章（3-1〜3-11） <a class="header-anchor" href="#星辰篇第3章-3-1〜3-11" aria-label="Permalink to &quot;星辰篇第3章（3-1〜3-11）&quot;">​</a></h3><p>星辰篇第三章。新限定キャラクター・茉夏（血肉）と波吕克斯（超維）が登場。</p><h3 id="星辰篇第4章-楽園-paradise-4-0〜4-16" tabindex="-1">星辰篇第4章：楽園（Paradise）（4-0〜4-16） <a class="header-anchor" href="#星辰篇第4章-楽園-paradise-4-0〜4-16" aria-label="Permalink to &quot;星辰篇第4章：楽園（Paradise）（4-0〜4-16）&quot;">​</a></h3><blockquote><p>「なぜ黒い太陽が空を覆ったのか？」</p></blockquote><p>星辰篇で最も難易度が跳ね上がる章。v2.4二周年版本で実装。新キャラタイプ「合唱（Chorus）」が登場し、诞妄·墨菲（深海合唱型）と徐（血肉合唱型）が実装された。</p><h2 id="後半ストーリーの特殊メカニクス" tabindex="-1">後半ストーリーの特殊メカニクス <a class="header-anchor" href="#後半ストーリーの特殊メカニクス" aria-label="Permalink to &quot;後半ストーリーの特殊メカニクス&quot;">​</a></h2><h3 id="融災黒潮-erosion-black-tide" tabindex="-1">融災黒潮（Erosion Black Tide） <a class="header-anchor" href="#融災黒潮-erosion-black-tide" aria-label="Permalink to &quot;融災黒潮（Erosion Black Tide）&quot;">​</a></h3><p>後半章節で出現する特殊なデバフメカニクス。以下の効果が含まれる：</p><table tabindex="0"><thead><tr><th style="text-align:left;">デバフ名</th><th style="text-align:left;">効果</th></tr></thead><tbody><tr><td style="text-align:left;">狂気衰竭</td><td style="text-align:left;">狂気獲得量を低下</td></tr><tr><td style="text-align:left;">銀鍵振盪</td><td style="text-align:left;">銀鍵エネルギーを妨害</td></tr><tr><td style="text-align:left;">怒海狂瀾</td><td style="text-align:left;">深海界域特殊効果</td></tr><tr><td style="text-align:left;">猩紅哺育</td><td style="text-align:left;">血肉界域特殊効果</td></tr><tr><td style="text-align:left;">彼界終途</td><td style="text-align:left;">超維界域特殊効果</td></tr><tr><td style="text-align:left;">来自遺忘</td><td style="text-align:left;">混沌界域特殊効果</td></tr></tbody></table><h2 id="関連ページ" tabindex="-1">関連ページ <a class="header-anchor" href="#関連ページ" aria-label="Permalink to &quot;関連ページ&quot;">​</a></h2><ul><li><a href="./">ストーリー概要</a></li><li><a href="./character-stories.html">キャラクターストーリー</a></li><li><a href="./worldbuilding.html">世界観設定</a></li><li><a href="./../stages/main.html">メインステージ</a></li></ul>',41)])])}const x=e(i,[["render",d]]);export{b as __pageData,x as default};
